async fn ping() -> &'static str {
    "pong"
}

async fn health() -> &'static str {
    "ok"
}

#[tok::main]
async fn main() {
    let app = Router::new()
        .route("/ping", get(ping))
        .route("/health", get(health));

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000")
        .await
        .expect("Failed to bind to 127.0.0.1:3000");

